import{_ as t,o as s,c as a,ag as r}from"./chunks/framework.ePeAWSvT.js";const o="/assets/monitor-messages.CY_Z1ZpJ.png",u=JSON.parse('{"title":"Messages","description":"","frontmatter":{},"headers":[],"relativePath":"guide/monitor-messages.md","filePath":"guide/monitor-messages.md"}'),n={name:"guide/monitor-messages.md"};function i(d,e,l,g,h,c){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="messages" tabindex="-1">Messages <a class="header-anchor" href="#messages" aria-label="Permalink to &quot;Messages&quot;">​</a></h1><p>The Messages page allows you to search and inspect individual integration messages. Filter by entity type, endpoint, date range, and more to find specific transactions.</p><p><img src="'+o+'" alt="Messages Page"></p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><ul><li><strong>Message Search</strong> — Filter messages by endpoint, entity type, date range, and status</li><li><strong>Message Details</strong> — View full message metadata including primary keys, receipts, and processing history</li><li><strong>Rerun Capability</strong> — Reprocess failed messages with a single click</li></ul><h2 id="view-and-manage-messages" tabindex="-1">View and Manage Messages <a class="header-anchor" href="#view-and-manage-messages" aria-label="Permalink to &quot;View and Manage Messages&quot;">​</a></h2><ol><li>Select <strong>Monitor</strong> &gt; <strong>Messages</strong>.</li><li>Then, use the table below to determine the next steps.</li></ol><table tabindex="0"><thead><tr><th>To</th><th>Do this</th></tr></thead><tbody><tr><td><strong>View the data</strong></td><td>All transaction data will be displayed in the table.</td></tr><tr><td><strong>Refresh the data</strong></td><td>Select <strong>Reload</strong>.</td></tr><tr><td><strong>View a specific time range</strong></td><td>Select <strong>Set Range</strong>. Select a pre-formulated <strong>Date Range</strong> (e.g. Last Hour) or select <strong>Custom</strong> to apply a specific date and time to view that data. Select <strong>Apply</strong>.</td></tr><tr><td><strong>Filter the Messages</strong></td><td>Select the <strong>filter</strong> icon in the header row of any column. Select and enter the required data (required fields vary based on the selected column). Select <strong>Apply</strong>. To clear any applied filters, select <strong>Reset</strong>.</td></tr><tr><td><strong>Sort the Messages</strong></td><td>Select the <strong>header row</strong> in the column to sort. A <strong>sort</strong> icon will appear in the header row of the column being sorted. Select the header once to sort in ascending order, twice to sort in descending order, and a third time to return to the default.</td></tr><tr><td><strong>Re-run the message</strong></td><td>Select <strong>Actions</strong> &gt; <strong>Re-Run Message</strong> in the appropriate row.</td></tr><tr><td><strong>View Details</strong></td><td>Select <strong>Actions</strong> &gt; <strong>View Details</strong> in the appropriate row. See <a href="#message-detail-tabs">Message Detail Tabs</a> below.</td></tr><tr><td><strong>View Record History</strong></td><td>Select <strong>Actions</strong> &gt; <strong>View Record History</strong> in the appropriate row. The record history for that message will open in a new browser tab, displaying all messages associated with that record, including all activity and errors with timestamps. From this screen, you can also select <strong>Actions</strong> &gt; <strong>Re-Run Message</strong> or <strong>Actions</strong> &gt; <strong>View Details</strong>.</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The <strong>Re-Run Message</strong> option should be used only if you understand the error and believe it has already been fixed in the triggering system.</p></div><h3 id="message-detail-tabs" tabindex="-1">Message Detail Tabs <a class="header-anchor" href="#message-detail-tabs" aria-label="Permalink to &quot;Message Detail Tabs&quot;">​</a></h3><p>When you select <strong>Actions</strong> &gt; <strong>View Details</strong>, a Message Details window appears with the following tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Description</th></tr></thead><tbody><tr><td><strong>Message</strong></td><td>View the message details in code view.</td></tr><tr><td><strong>Receipts</strong></td><td>View all subscribers that picked up that message and tried to process it, as well as Error Log data.</td></tr><tr><td><strong>Outputs</strong></td><td>Data will be populated if the subscriber endpoint has an entity type of &quot;File,&quot; and will include a link to download the file that was created when the integration was triggered to execute.</td></tr><tr><td><strong>Re-Run History</strong></td><td>View an audit of the previous re-runs, including the Date, By, and any Comments associated with that re-run.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>It is advised to view the message details, which provides an opportunity to analyze the error details and formulate a fix; however, as needed, you can also select to <strong>Re-Run</strong> the message from the details view.</p></div><div class="info custom-block"><p class="custom-block-title">Example</p><p>Viewing Record History is a good way to see if the error has already been resolved. For example, if an error happened when syncing a sales order at 8 PM, but was successful when it ran again at 9 PM, both messages would appear in the history.</p></div><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./monitor-dashboard.html">Monitor Dashboard</a> — View platform health at a glance</li><li><a href="./monitor-error-logs.html">Error Logs</a> — Investigate processing errors</li><li><a href="./monitor-maintain-index.html">Maintain Index</a> — Manage entity search indexes</li></ul>',16)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
